import { createClient } from '@/lib/supabase/server';
import { Journal } from '@/types';
import Link from 'next/link';
import { Calendar, ArrowRight } from 'lucide-react';

export const metadata = {
  title: 'Spiritual Journal | Advaitha Yogam',
  description: 'Reflections, insights, and teachings on the path of Advaitha.',
};

export default async function JournalsPage() {
  const supabase = await createClient();
  
  const { data: journals, error } = await supabase
    .from('journals')
    .select('*')
    .eq('status', 'published')
    .order('published_at', { ascending: false });

  return (
    <div className="min-h-screen bg-[#FAFAFA] py-20 px-4 sm:px-6 lg:px-8 font-[family-name:var(--font-outfit)]">
      <div className="max-w-5xl mx-auto">
        <div className="text-center mb-16">
          <h1 className="text-4xl md:text-5xl font-bold font-[family-name:var(--font-cormorant)] text-[#2D5A3D] mb-4">
            Spiritual Journal
          </h1>
          <p className="text-lg text-gray-600 max-w-2xl mx-auto">
            Reflections, insights, and teachings on the path of Yoga and Vedanta.
          </p>
        </div>

        <div className="space-y-12">
          {journals?.map((journal: Journal) => (
            <article key={journal.id} className="bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 border border-gray-100 flex flex-col md:flex-row group">
              {journal.image_url && (
                <div className="md:w-2/5 overflow-hidden">
                  <img 
                    src={journal.image_url} 
                    alt={journal.title} 
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                  />
                </div>
              )}
              <div className={`p-8 md:p-10 flex flex-col ${journal.image_url ? 'md:w-3/5' : 'w-full'}`}>
                <div className="flex flex-wrap gap-2 mb-4">
                  {journal.tags?.map(tag => (
                    <span key={tag} className="text-xs font-semibold tracking-wider uppercase text-amber-600 bg-amber-50 px-2 py-1 rounded">
                      {tag}
                    </span>
                  ))}
                </div>
                
                <h2 className="text-2xl md:text-3xl font-bold font-[family-name:var(--font-cormorant)] text-gray-900 mb-4 leading-tight group-hover:text-amber-600 transition-colors">
                  <Link href={`/journals/${journal.slug}`}>
                    {journal.title}
                  </Link>
                </h2>
                
                {journal.content && (
                  <p className="text-gray-600 mb-6 line-clamp-3 leading-relaxed">
                    {journal.content.replace(/[#*`_]/g, '').slice(0, 200)}...
                  </p>
                )}
                
                <div className="mt-auto flex items-center justify-between pt-6 border-t border-gray-100">
                  <div className="flex items-center gap-2 text-sm text-gray-500">
                    <Calendar size={16} />
                    <span>
                      {journal.published_at 
                        ? new Date(journal.published_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })
                        : new Date(journal.created_at).toLocaleDateString(undefined, { year: 'numeric', month: 'long', day: 'numeric' })
                      }
                    </span>
                  </div>
                  
                  <Link href={`/journals/${journal.slug}`} className="inline-flex items-center gap-2 text-sm font-semibold text-amber-600 hover:text-amber-700 transition-colors">
                    Read Article <ArrowRight size={16} />
                  </Link>
                </div>
              </div>
            </article>
          ))}
          
          {(!journals || journals.length === 0) && (
            <div className="py-20 text-center bg-white rounded-2xl border border-gray-100">
              <p className="text-gray-500 text-lg">No journal entries published yet. Please check back soon.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
